// Interface: a contract that implementing classes must follow
interface PaymentMethod {
    // All implementors must provide this method
    void pay(double amount);
}

// CreditCard implements PaymentMethod in its own way
class CreditCard implements PaymentMethod {
    public void pay(double amount) {
        System.out.println("Charged $" + amount + " to credit card");
    }
}

// PayPal implements the same interface differently
class PayPal implements PaymentMethod {
    public void pay(double amount) {
        System.out.println("Processed $" + amount + " via PayPal");
    }
}
